mapper.select:
SELECT
FROM mcp_gateway_auth
ORDER BY create_time DESC LIMIT #{offset}, #{pageSize}

mapper.update:
UPDATE mcp_gateway_auth
SET status = #{status},
update_time = NOW(),
version = version + 1
WHERE gateway_id = #{gatewayId}
AND api_key = #{apiKey}
AND version = #{oldVersion}

UPDATE mcp_gateway_auth
SET status = 0, update_time = NOW()
WHERE gateway_id = #{gatewayId} AND api_key = #{apiKey}
